// Transform Shopify products to Walmart feed format
const products = $input.first().json.products || [];

if (products.length === 0) {
  return [{ json: { message: 'No products updated in last 7 days', count: 0 } }];
}

const EXCLUDE = ['lnk.nebraska','lnk nebraska','lnk'];
const eligible = products.filter(p => !EXCLUDE.some(e => (p.vendor||'').toLowerCase().includes(e)));
const walmartItems = eligible.map(product => {
  const variant = product.variants[0];
  const image = product.images[0]?.src || '';

  // Walmart requires GTIN/UPC - use Shopify barcode or SKU
  const gtin = variant.barcode || variant.sku || '';

  return {
    sku: variant.sku || `WW-${product.id}`,
    productName: product.title,
    shortDescription: product.body_html?.replace(/<[^>]+>/g, '').substring(0, 500) || '',
    price: parseFloat(variant.price),
    currency: 'USD',
    quantity: variant.inventory_quantity || 0,
    mainImageUrl: image,
    productType: product.product_type || 'Health & Beauty',
    brand: product.vendor || 'Wax and Wane',
    gtin: gtin,
    shopify_id: product.id,
    shopify_handle: product.handle
  };
});

return walmartItems.map(item => ({ json: item }));

const cfg = $('Set Walmart Config').first().json;
const item = $input.first().json;
if (item.message) return [{ json: item }];
if (item.status === 'logged') return [{ json: item }];

const exclude = ['lnk.nebraska', 'lnk nebraska'];
const brand = String(item.brand || '').toLowerCase();
if (exclude.some(e => brand.includes(e))) {
  return [{ json: { status: 'skipped', reason: 'LNK vendor excluded', sku: item.sku } }];
}

if (!cfg.walmartClientId || !cfg.walmartClientSecret) {
  return [{ json: { status: 'logged', item: item.productName, note: 'Set WALMART_CLIENT_ID/SECRET in vault' } }];
}

// OAuth token (client credentials)
const tokenResp = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://marketplace.walmartapis.com/v3/token',
  headers: {
    'WM_SVC.NAME': 'Walmart Marketplace',
    'WM_QOS.CORRELATION_ID': Date.now().toString(),
    'Authorization': 'Basic ' + Buffer.from(`${cfg.walmartClientId}:${cfg.walmartClientSecret}`).toString('base64'),
    'Content-Type': 'application/x-www-form-urlencoded',
  },
  body: 'grant_type=client_credentials',
});
const accessToken = tokenResp.access_token;
if (!accessToken) throw new Error('Walmart token failed');

const payload = {
  sku: item.sku,
  productName: item.productName,
  price: { currency: 'USD', amount: item.price },
  publishedStatus: 'PUBLISHED',
};
const resp = await this.helpers.httpRequest({
  method: 'PUT',
  url: `https://marketplace.walmartapis.com/v3/items/${encodeURIComponent(item.sku)}`,
  headers: {
    'WM_SEC.ACCESS_TOKEN': accessToken,
    'WM_SVC.NAME': 'Walmart Marketplace',
    'WM_QOS.CORRELATION_ID': Date.now().toString(),
    'Content-Type': 'application/json',
    'Accept': 'application/json',
  },
  body: payload,
  json: true,
});
return [{ json: { status: 'synced', sku: item.sku, walmart: resp } }];
